mapper.select:
SELECT o.id AS order_id, o.code AS order_code, CONCAT(p.name, ' 외 ', COUNT(*) - 1, '건') AS product_summary, o.status, o.created_at, o.total_amount, f.name AS franchise_name FROM orders o JOIN franchise f ON o.franchise_id = f.id JOIN product_order po ON o.id = po.order_id JOIN product p ON po.product_id = p.id
o.franchise_id IN ( SELECT id FROM franchise WHERE owner_id = #{ownerId} )
AND o.code LIKE CONCAT('%', #{code}, '%')
AND EXISTS ( SELECT 1 FROM product_order po2 JOIN product p2 ON po2.product_id = p2.id WHERE po2.order_id = o.id AND p2.name LIKE CONCAT('%', #{product}, '%') )
AND o.status IN
#{s}
AND DATE(o.created_at) BETWEEN #{startDate} AND #{endDate}
GROUP BY o.id ORDER BY o.created_at DESC LIMIT #{size} OFFSET #{offset}
